```class Solution {
public:
    vector<string> topKFrequent(vector<string>& words, int k) {
        unordered_map<string, int> count;
        for (string word : words) {
            count[word]++;
        }
        priority_queue<pair<int, string>> pq;
        for (auto p : count) {
            pq.push({p.second, p.first});
        }
        vector<string> res;
        while (k--) {
            res.push_back(pq.top().second);
            pq.pop();
        }
        return res;
    }
};```
